import 'package:flutter/material.dart';
import 'api_client.dart';
import 'auth_service.dart';
import 'login_page.dart';
class HomePage extends StatefulWidget{const HomePage({super.key});@override State<HomePage> createState()=>_HomePageState();}
class _HomePageState extends State<HomePage>{List<dynamic>orders=[];List<dynamic>products=[];String?error;@override void initState(){super.initState();load();}Future<void>load()async{try{final dio=await ApiClient.instance.dio;final o=await dio.get('/merchant/orders');final p=await dio.get('/merchant/products');setState((){orders=o.data['data']['data']??[];products=p.data['data']['data']??[];error=null;});}catch(e){setState(()=>error=e.toString());}}Future<void>logout()async{await AuthService().logout();if(!mounted)return;Navigator.of(context).pushAndRemoveUntil(MaterialPageRoute(builder:(_)=>const LoginPage(title:'IAS Market Merchant',role:'merchant',deviceName:'IAS Market Merchant Android')),(_)=>false);}@override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:const Text('IAS Market Merchant'),actions:[IconButton(onPressed:logout,icon:const Icon(Icons.logout))]),body:RefreshIndicator(onRefresh:load,child:ListView(padding:const EdgeInsets.all(16),children:[if(error!=null)Text(error!,style:const TextStyle(color:Colors.red)),Text('Pesanan masuk',style:Theme.of(context).textTheme.titleLarge),...orders.take(15).map((o)=>Card(child:ListTile(title:Text('${o['order_number']}'),subtitle:Text('${o['status']}'),trailing:Text('Rp ${o['total']}')))),const SizedBox(height:16),Text('Produk',style:Theme.of(context).textTheme.titleLarge),...products.take(15).map((p)=>Card(child:ListTile(title:Text('${p['name']}'),subtitle:Text('Stok ${p['stock']}'),trailing:Text('Rp ${p['price']}'))))])));}
